struct Triangle {
    double ax, ay, bx, by, cx, cy;
    Triangle(double ax_, double ay_, double bx_, double by_, double cx_, double cy_)
        : ax(ax_), ay(ay_), bx(bx_), by(by_), cx(cx_), cy(cy_) {}
    double area() const {
        double v = (bx-ax)*(cy-ay) - (cx-ax)*(by-ay);
        return (v < 0.0 ? -v : v) * 0.5;
    }
