        double d1 = sqrt((bx-ax)*(bx-ax) + (by-ay)*(by-ay));
        double d2 = sqrt((cx-bx)*(cx-bx) + (cy-by)*(cy-by));
        double d3 = sqrt((ax-cx)*(ax-cx) + (ay-cy)*(ay-cy));
        return d1 + d2 + d3;
    }
};

